<?php
namespace Tests\Feature;
use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Domain\Inventory\Instances\ItemInstanceService;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Domain\Inventory\Instances\Refinement\ItemRefinementService;use App\Domain\Inventory\Instances\Refinement\RefinementTokenService;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\Shop;use App\Models\ShopSale;use Carbon\CarbonImmutable;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use InvalidArgumentException;use LogicException;use Tests\TestCase;
final class ItemInstanceSoldLifecycleTest extends TestCase{use RefreshDatabase;private $origin=9000;
public function test_available_transitions_to_terminal_sold_with_append_only_audit(){$data=$this->fixture();$previous=ItemInstanceEvent::factory()->create(['item_instance_id'=>$data['instance']->id]);$now=CarbonImmutable::parse('2026-07-22 15:00:00');DB::transaction(function()use($data,$now){$locked=ItemInstance::whereKey($data['instance']->id)->lockForUpdate()->firstOrFail();app(ItemInstanceService::class)->markSoldToShopLocked($data['character'],$locked,$data['sale'],$now);});$instance=$data['instance']->fresh();$this->assertTrue($instance->isSold());$this->assertSame($data['character']->id,$instance->character_id);$this->assertSame($data['item']->id,$instance->item_id);$this->assertSame('legacy_inventory',$instance->origin_type);$this->assertDatabaseHas('item_instance_events',['id'=>$previous->id]);$event=ItemInstanceEvent::where('event_type',ItemInstanceEventType::SOLD_TO_SHOP)->firstOrFail();foreach(['shop_sale_id','shop_id','character_id','item_id','item_instance_uuid','refinement_level','status_before','sold_at']as$key)$this->assertArrayHasKey($key,$event->metadata);$this->assertSame($data['sale']->id,$event->source_id);try{$event->update(['metadata'=>[]]);$this->fail('Event update was accepted.');}catch(LogicException $e){$this->assertTrue(true);}try{$event->delete();$this->fail('Event deletion was accepted.');}catch(LogicException $e){$this->assertTrue(true);}}
public function test_equipped_and_sold_instances_cannot_be_sold_and_terminal_transitions_are_rejected(){$equipped=$this->fixture(ItemInstanceStatus::EQUIPPED,true);try{DB::transaction(function()use($equipped){app(ItemInstanceService::class)->markSoldToShopLocked($equipped['character'],$equipped['instance'],$equipped['sale'],CarbonImmutable::now());});$this->fail('Equipped instance was sold.');}catch(InvalidArgumentException $e){$this->assertTrue(true);}$this->assertSame(ItemInstanceStatus::EQUIPPED,$equipped['instance']->fresh()->status);$this->assertSame(0,ItemInstanceEvent::where('event_type',ItemInstanceEventType::SOLD_TO_SHOP)->count());$sold=$this->fixture();DB::transaction(function()use($sold){app(ItemInstanceService::class)->markSoldToShopLocked($sold['character'],$sold['instance'],$sold['sale'],CarbonImmutable::now());});foreach([ItemInstanceStatus::AVAILABLE,ItemInstanceStatus::EQUIPPED]as$status){$instance=$sold['instance']->fresh();try{$instance->status=$status;$instance->save();$this->fail('Terminal state was left.');}catch(LogicException $e){$this->assertTrue(true);}}try{DB::transaction(function()use($sold){app(ItemInstanceService::class)->markSoldToShopLocked($sold['character'],$sold['instance']->fresh(),$sold['sale'],CarbonImmutable::now());});$this->fail('Sold twice.');}catch(InvalidArgumentException $e){$this->assertTrue(true);}$this->assertSame(1,ItemInstanceEvent::where('event_type',ItemInstanceEventType::SOLD_TO_SHOP)->count());}
public function test_sold_is_excluded_from_inventory_capacity_overview_and_equipment(){$data=$this->fixture();$other=ItemInstance::factory()->create(['character_id'=>$data['character']->id]);$before=app(PendingRewardCapacityService::class)->snapshot($data['character'])->toArray();DB::transaction(function()use($data){app(ItemInstanceService::class)->markSoldToShopLocked($data['character'],$data['instance'],$data['sale'],CarbonImmutable::now());});$after=app(PendingRewardCapacityService::class)->snapshot($data['character'])->toArray();$summary=app(CharacterInventorySummaryService::class)->snapshot($data['character']);$this->assertSame($before['current_used_slots']-1,$after['current_used_slots']);$this->assertSame([$other->uuid],collect($summary['item_instances'])->pluck('uuid')->all());try{app(CharacterEquipmentService::class)->equip($data['character'],$data['instance']->uuid,'main_hand');$this->fail('Sold instance was equipped.');}catch(\Throwable $e){$this->assertTrue(true);}$this->actingAs($data['character']->user)->get(route('characters.overview',$data['character']))->assertOk()->assertDontSee($data['instance']->uuid);}
public function test_sold_cannot_be_refined_and_no_resources_or_events_change(){$data=$this->fixture();DB::transaction(function()use($data){app(ItemInstanceService::class)->markSoldToShopLocked($data['character'],$data['instance'],$data['sale'],CarbonImmutable::now());});$instance=$data['instance']->fresh();$token=app(RefinementTokenService::class)->issue($data['character'],$instance);$events=ItemInstanceEvent::count();try{app(ItemRefinementService::class)->refine($data['character'],$instance,$token);$this->fail('Sold instance was refined.');}catch(InvalidArgumentException $e){$this->assertStringContainsString('status',$e->getMessage());}$this->assertSame(0,$instance->fresh()->refinement_level);$this->assertSame($events,ItemInstanceEvent::count());}
public function test_event_failure_rolls_back_sold_status(){$data=$this->fixture();ItemInstanceEvent::create(['item_instance_id'=>$data['instance']->id,'operation_uuid'=>$data['sale']->idempotency_key,'event_type'=>ItemInstanceEventType::SOLD_TO_SHOP,'actor_character_id'=>$data['character']->id,'from_character_id'=>$data['character']->id,'to_character_id'=>null,'from_item_id'=>$data['item']->id,'to_item_id'=>$data['item']->id,'refinement_before'=>0,'refinement_after'=>0,'source_type'=>'shop_sale','source_id'=>$data['sale']->id,'metadata'=>[],'occurred_at'=>now(),'created_at'=>now()]);try{DB::transaction(function()use($data){$locked=ItemInstance::whereKey($data['instance']->id)->lockForUpdate()->firstOrFail();app(ItemInstanceService::class)->markSoldToShopLocked($data['character'],$locked,$data['sale'],CarbonImmutable::now());});$this->fail('Duplicate event was accepted.');}catch(QueryException $e){$this->assertSame('23000',(string)$e->getCode());}$this->assertSame(ItemInstanceStatus::AVAILABLE,$data['instance']->fresh()->status);$this->assertSame(1,ItemInstanceEvent::where('event_type',ItemInstanceEventType::SOLD_TO_SHOP)->count());}
private function fixture($status=ItemInstanceStatus::AVAILABLE,$equipment=false){$character=Character::factory()->selected()->create();$item=Item::create(['code'=>'sold_item_'.Str::random(10),'name'=>'Sold lifecycle item','item_type'=>'equipment','equipment_type'=>'weapon','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'is_sellable'=>true,'sell_price'=>20,'status'=>'active']);$instance=ItemInstance::create(['uuid'=>(string)Str::uuid(),'character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>0,'status'=>$status,'origin_type'=>'legacy_inventory','origin_id'=>$this->origin++,'origin_unit_index'=>1,'acquired_at'=>now()]);if($equipment)CharacterEquipment::create(['character_id'=>$character->id,'slot'=>'main_hand','item_instance_id'=>$instance->id,'equipped_at'=>now()]);$shop=Shop::factory()->create(['buys_items'=>true]);$sale=ShopSale::create(['shop_id'=>$shop->id,'character_id'=>$character->id,'item_id'=>$item->id,'item_instance_id'=>$instance->id,'source_type'=>'instance','quantity_sold'=>1,'unit_gold'=>20,'total_gold'=>20,'idempotency_key'=>(string)Str::uuid(),'sold_at'=>now()]);return compact('character','item','instance','shop','sale');}}
